import { Outlet, NavLink, useNavigate } from 'react-router-dom';

const T = "-apple-system, BlinkMacSystemFont, 'SF Pro Display', 'Segoe UI', sans-serif";
const GOLD = '#D4AF37';

const NAV = [
  { to: '/admin', label: 'Overview', icon: '▦', end: true },
  { to: '/admin/create-event', label: 'Create Event', icon: '+' },
  { to: '/admin/manage-events', label: 'Manage Events', icon: '≡' },
  { to: '/admin/bookings', label: 'All Bookings', icon: '◈' },
];

export default function DashboardLayout() {
  const navigate = useNavigate();
  const user = (() => { try { return JSON.parse(localStorage.getItem('user') || '{}'); } catch { return {}; } })();

  const logout = () => {
    localStorage.removeItem('token');
    localStorage.removeItem('user');
    navigate('/login');
  };

  return (
    <div style={{ display: 'flex', minHeight: '100vh', background: '#000', fontFamily: T }}>

      {/* Sidebar */}
      <aside style={{
        width: '240px', flexShrink: 0,
        background: '#0a0a0a',
        borderRight: '1px solid rgba(255,255,255,0.07)',
        display: 'flex', flexDirection: 'column',
        position: 'sticky', top: 0, height: '100vh',
      }}>
        {/* Logo */}
        <div style={{ padding: '1.5rem 1.5rem 1rem', borderBottom: '1px solid rgba(255,255,255,0.06)' }}>
          <h1 style={{ fontWeight: 700, fontSize: '1.2rem', color: '#fff', margin: '0 0 2px', letterSpacing: '-0.5px' }}>
            Nex<span style={{ color: GOLD }}>Event</span>
          </h1>
          <p style={{ color: '#444', fontSize: '0.72rem', fontWeight: 700, letterSpacing: '1.5px', textTransform: 'uppercase', margin: 0 }}>Admin Panel</p>
        </div>

        {/* User */}
        <div style={{ padding: '1rem 1.5rem', borderBottom: '1px solid rgba(255,255,255,0.06)' }}>
          <div style={{ display: 'flex', alignItems: 'center', gap: '10px' }}>
            <div style={{ width: '34px', height: '34px', borderRadius: '50%', background: 'rgba(212,175,55,0.1)', border: '1px solid rgba(212,175,55,0.2)', display: 'flex', alignItems: 'center', justifyContent: 'center', color: GOLD, fontWeight: 700, fontSize: '0.85rem', flexShrink: 0 }}>
              {(user?.name || user?.email || 'A')[0].toUpperCase()}
            </div>
            <div>
              <p style={{ color: '#fff', fontSize: '0.84rem', fontWeight: 600, margin: 0 }}>{user?.name || 'Admin'}</p>
              <p style={{ color: '#555', fontSize: '0.72rem', margin: 0 }}>Administrator</p>
            </div>
          </div>
        </div>

        {/* Nav */}
        <nav style={{ padding: '1rem 0.75rem', flex: 1 }}>
          {NAV.map(({ to, label, icon, end }) => (
            <NavLink key={to} to={to} end={end} style={({ isActive }) => ({
              display: 'flex', alignItems: 'center', gap: '10px',
              padding: '10px 12px', borderRadius: '10px', marginBottom: '2px',
              textDecoration: 'none', transition: 'all 0.2s',
              background: isActive ? 'rgba(212,175,55,0.1)' : 'transparent',
              color: isActive ? GOLD : '#666',
              border: `1px solid ${isActive ? 'rgba(212,175,55,0.2)' : 'transparent'}`,
            })}>
              <span style={{ fontSize: '1rem', width: '18px', textAlign: 'center' }}>{icon}</span>
              <span style={{ fontSize: '0.86rem', fontWeight: 600 }}>{label}</span>
            </NavLink>
          ))}
        </nav>

        {/* Logout */}
        <div style={{ padding: '1rem 0.75rem', borderTop: '1px solid rgba(255,255,255,0.06)' }}>
          <button onClick={logout} style={{
            width: '100%', padding: '10px 12px', background: 'transparent',
            border: '1px solid rgba(255,69,58,0.2)', borderRadius: '10px',
            color: '#FF453A', cursor: 'pointer', fontFamily: T,
            fontSize: '0.86rem', fontWeight: 600, textAlign: 'left',
            display: 'flex', alignItems: 'center', gap: '10px', transition: 'all 0.2s',
          }}
            onMouseEnter={e => e.currentTarget.style.background = 'rgba(255,69,58,0.08)'}
            onMouseLeave={e => e.currentTarget.style.background = 'transparent'}>
            <span>⏻</span> Sign Out
          </button>
        </div>
      </aside>

      {/* Main */}
      <main style={{ flex: 1, overflow: 'auto' }}>
        <Outlet />
      </main>
    </div>
  );
}
